# ──────────────────────────────────────────────
# DATABASE
# ──────────────────────────────────────────────
@st.cache_resource
def get_conn():
    # Make sure the folder for the database exists (e.g. ~/StockInventory).
    folder = os.path.dirname(os.path.abspath(DB_PATH))
    if folder:
        try:
            os.makedirs(folder, exist_ok=True)
        except Exception:
            pass
    conn = sqlite3.connect(DB_PATH, check_same_thread=False, timeout=30)
    # Wait instead of failing immediately if the file is briefly busy.
    try:
        conn.execute("PRAGMA busy_timeout=5000;")
    except Exception:
        pass
    # WAL is faster/safer, but isn't supported on some drives (network/USB).
    # Fall back to the default journal so the app still works there.
    try:
        conn.execute("PRAGMA journal_mode=WAL;")
    except Exception:
        try:
            conn.execute("PRAGMA journal_mode=DELETE;")
        except Exception:
            pass
    return conn


def init_db():
    c = get_conn()
    c.executescript("""
    CREATE TABLE IF NOT EXISTS items (
        name TEXT PRIMARY KEY,
        unit TEXT,
        category TEXT,
        initial_stock REAL DEFAULT 0,
        reorder_pct REAL DEFAULT 20,
        expiry TEXT,
        created_at TEXT);
    CREATE TABLE IF NOT EXISTS usage_log (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        item_name TEXT, use_date TEXT, quantity REAL, note TEXT,
        recorded_by TEXT, logged_at TEXT);
    CREATE TABLE IF NOT EXISTS restock_log (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        item_name TEXT, restock_date TEXT, quantity REAL, note TEXT,
        recorded_by TEXT, logged_at TEXT);
    CREATE TABLE IF NOT EXISTS settings (key TEXT PRIMARY KEY, value TEXT);
    CREATE TABLE IF NOT EXISTS audit_log (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        at TEXT, who TEXT, action TEXT, detail TEXT);
    """)
    c.commit()
    migrate()


def get_setting(key, default=""):
    row = get_conn().execute("SELECT value FROM settings WHERE key=?", (key,)).fetchone()
    return row[0] if row and row[0] is not None else default


_DATA_VERSION = 0
_STATUS_CACHE = {"key": None, "df": None}


def bump_data_version():
    """Invalidate the in-run status cache after any change to the data."""
    global _DATA_VERSION
    _DATA_VERSION += 1


def set_setting(key, value):
    c = get_conn()
    c.execute("INSERT INTO settings(key, value) VALUES(?, ?) "
              "ON CONFLICT(key) DO UPDATE SET value=excluded.value", (key, str(value)))
    c.commit()
    bump_data_version()


def migrate():
    """Add any columns missing from an older database so upgrading in place is safe.
    (CREATE TABLE IF NOT EXISTS won't alter a table that already exists.)"""
    c = get_conn()

    def cols(t):
        return {r[1] for r in c.execute(f"PRAGMA table_info({t})").fetchall()}

    item_cols = cols("items")
    for name, ddl in (("unit", "TEXT"), ("category", "TEXT"),
                      ("initial_stock", "REAL DEFAULT 0"),
                      ("reorder_pct", "REAL DEFAULT 20"), ("expiry", "TEXT"),
                      ("created_at", "TEXT")):
        if name not in item_cols:
            c.execute(f"ALTER TABLE items ADD COLUMN {name} {ddl}")
    for t in ("usage_log", "restock_log"):
        tc = cols(t)
        if "note" not in tc:
            c.execute(f"ALTER TABLE {t} ADD COLUMN note TEXT")
        if "recorded_by" not in tc:
            c.execute(f"ALTER TABLE {t} ADD COLUMN recorded_by TEXT")
    c.execute("CREATE TABLE IF NOT EXISTS audit_log ("
              "id INTEGER PRIMARY KEY AUTOINCREMENT, at TEXT, who TEXT, "
              "action TEXT, detail TEXT)")
    # Indexes that speed up the per-item history lookups and date filters.
    c.execute("CREATE INDEX IF NOT EXISTS idx_usage_item ON usage_log(item_name)")
    c.execute("CREATE INDEX IF NOT EXISTS idx_usage_date ON usage_log(use_date)")
    c.execute("CREATE INDEX IF NOT EXISTS idx_restock_item ON restock_log(item_name)")
    c.execute("CREATE INDEX IF NOT EXISTS idx_restock_date ON restock_log(restock_date)")
    c.commit()


def current_user():
    return get_setting("current_user", "").strip()


def audit(action, detail=""):
    """Record an action in the audit trail (best-effort, never breaks the app)."""
    try:
        c = get_conn()
        c.execute("INSERT INTO audit_log(at, who, action, detail) VALUES(?,?,?,?)",
                  (datetime.now().isoformat(timespec="seconds"),
                   current_user() or "—", action, str(detail)[:500]))
        c.commit()
    except Exception:
        pass
    bump_data_version()


def add_item(name, unit, category, initial_stock, reorder_pct, expiry=None):
    c = get_conn()
    c.execute("INSERT INTO items(name, unit, category, initial_stock, reorder_pct, "
              "expiry, created_at) VALUES(?,?,?,?,?,?,?)",
              (name, unit, category, float(initial_stock), float(reorder_pct),
               expiry or None, datetime.now().isoformat(timespec="seconds")))
    c.commit()
    audit("Add item", f"{name} (start {initial_stock} {unit})")


def update_item(name, unit, category, initial_stock, reorder_pct, expiry=None):
    c = get_conn()
    c.execute("UPDATE items SET unit=?, category=?, initial_stock=?, reorder_pct=?, "
              "expiry=? WHERE name=?",
              (unit, category, float(initial_stock), float(reorder_pct),
               expiry or None, name))
    c.commit()
    audit("Edit item", name)


def delete_item(name):
    c = get_conn()
    c.execute("DELETE FROM items WHERE name=?", (name,))
    c.execute("DELETE FROM usage_log WHERE item_name=?", (name,))
    c.execute("DELETE FROM restock_log WHERE item_name=?", (name,))
    c.commit()
    audit("Delete item", name)


def log_usage(name, d, qty, note="", recorded_by=None):
    c = get_conn()
    c.execute("INSERT INTO usage_log(item_name, use_date, quantity, note, "
              "recorded_by, logged_at) VALUES(?,?,?,?,?,?)",
              (name, d.isoformat(), float(qty), note,
               (recorded_by or current_user() or None),
               datetime.now().isoformat(timespec="seconds")))
    c.commit()
    audit("Log usage", f"{name}: {qty}")


def log_restock(name, d, qty, note="", recorded_by=None):
    c = get_conn()
    c.execute("INSERT INTO restock_log(item_name, restock_date, quantity, note, "
              "recorded_by, logged_at) VALUES(?,?,?,?,?,?)",
              (name, d.isoformat(), float(qty), note,
               (recorded_by or current_user() or None),
               datetime.now().isoformat(timespec="seconds")))
    c.commit()
    audit("Log restock", f"{name}: {qty}")


def update_log_entry(table, entry_id, d, qty, note=""):
    """Edit a past usage or restock entry. table is 'usage_log' or 'restock_log'."""
    datecol = "use_date" if table == "usage_log" else "restock_date"
    c = get_conn()
    c.execute(f"UPDATE {table} SET {datecol}=?, quantity=?, note=? WHERE id=?",
              (d.isoformat(), float(qty), note, int(entry_id)))
    c.commit()
    audit("Edit entry", f"{table} #{entry_id} -> {qty} on {d.isoformat()}")


def delete_log_entry(table, entry_id):
    c = get_conn()
    c.execute(f"DELETE FROM {table} WHERE id=?", (int(entry_id),))
    c.commit()
    audit("Delete entry", f"{table} #{entry_id}")


def item_exists(name):
    return get_conn().execute("SELECT 1 FROM items WHERE name=?", (name,)).fetchone() is not None


def get_item_names():
    return [r[0] for r in get_conn().execute("SELECT name FROM items ORDER BY name").fetchall()]


# ──────────────────────────────────────────────
# SETTINGS-DRIVEN THRESHOLDS / EXPIRY
# ──────────────────────────────────────────────
def moderate_threshold():
    try:
        v = float(get_setting("moderate_pct", "50"))
        return min(99.0, max(1.0, v))
    except Exception:
        return 50.0


def expiry_window_days():
    try:
        return max(1, int(float(get_setting("expiry_soon_days", "30"))))
    except Exception:
        return 30


def _parse_date(s):
    if not s:
        return None
    try:
        return datetime.strptime(str(s)[:10], "%Y-%m-%d").date()
    except Exception:
        return None


def expiry_status(expiry_str, today=None, window=None):
    """Return 'Expired', 'Expiring soon', 'OK', or '' (no date) for an expiry date."""
    d = _parse_date(expiry_str)
    if d is None:
        return ""
    today = today or date.today()
    window = window or expiry_window_days()
    if d < today:
        return "Expired"
    if (d - today).days <= window:
        return "Expiring soon"
    return "OK"


def avg_daily_usage(name, days=30, conn=None):
    """Average units used per day over the trailing `days` (uses real usage history)."""
    c = conn if conn is not None else get_conn()
    since = (date.today() - timedelta(days=days)).isoformat()
    row = c.execute("SELECT SUM(quantity) FROM usage_log WHERE item_name=? AND use_date>=?",
                    (name, since)).fetchone()
    total = (row[0] or 0.0) if row else 0.0
    return float(total) / float(days) if days > 0 else 0.0


# ──────────────────────────────────────────────
# AUTOMATIC BACKUPS
# ──────────────────────────────────────────────
def backups_dir():
    d = os.path.join(os.path.expanduser("~"), "StockInventory", "Backups")
    os.makedirs(d, exist_ok=True)
    return d


def auto_backup(reason="auto", keep=20):
    """Copy the working database into the Backups folder; prune to the last `keep`."""
    import shutil
    try:
        src = DB_PATH
        if not os.path.exists(src):
            return None
        # Flush the write-ahead log into the main file so the copy is self-contained.
        try:
            conn = get_conn()
            conn.execute("PRAGMA wal_checkpoint(TRUNCATE)")
            conn.commit()
        except Exception:
            pass
        stamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        safe = "".join(ch if ch.isalnum() else "_" for ch in reason)[:24] or "auto"
        dest = os.path.join(backups_dir(), f"backup_{stamp}_{safe}.db")
        shutil.copy2(src, dest)
        files = sorted(list_backups(), key=lambda p: p, reverse=True)
        for old in files[keep:]:
            try:
                os.remove(os.path.join(backups_dir(), old))
            except Exception:
                pass
        return dest
    except Exception:
        return None


def list_backups():
    try:
        return sorted((f for f in os.listdir(backups_dir())
                       if f.startswith("backup_") and f.endswith(".db")), reverse=True)
    except Exception:
        return []


def restore_backup(filename):
    """Replace the working database with a chosen backup (a safety copy is made first)."""
    import shutil
    path = os.path.join(backups_dir(), filename)
    if not os.path.exists(path):
        raise FileNotFoundError(filename)
    auto_backup("before_restore")
    try:
        get_conn().close()
    except Exception:
        pass
    try:
        st.cache_resource.clear()
    except Exception:
        pass
    # Remove the live DB and its write-ahead sidecars so nothing stale replays
    # over the restored data, then drop the chosen backup in its place.
    for suffix in ("-wal", "-shm", ""):
        try:
            os.remove(DB_PATH + suffix)
        except FileNotFoundError:
            pass
        except Exception:
            pass
    shutil.copy2(path, DB_PATH)
    audit("Restore backup", filename)


# ──────────────────────────────────────────────
# PIN / PASSWORD LOCK  (sha256 + per-install salt)
# ──────────────────────────────────────────────
def _hash_pin(pin, salt):
    import hashlib
    return hashlib.sha256((salt + ":" + str(pin)).encode("utf-8")).hexdigest()


def pin_is_set():
    return bool(get_setting("pin_hash", ""))


def set_pin(pin):
    import secrets
    salt = secrets.token_hex(8)
    set_setting("pin_salt", salt)
    set_setting("pin_hash", _hash_pin(pin, salt))
    audit("Set/*change PIN")


def clear_pin():
    set_setting("pin_hash", "")
    set_setting("pin_salt", "")
    audit("Remove PIN")


def check_pin(pin):
    salt = get_setting("pin_salt", "")
    stored = get_setting("pin_hash", "")
    return bool(stored) and _hash_pin(pin, salt) == stored


# ──────────────────────────────────────────────
# ACCOUNT  (Google / work email + password, stored locally)
# ──────────────────────────────────────────────
def account_exists():
    return bool(get_setting("account_email", ""))


def _valid_email(email):
    email = (email or "").strip()
    return "@" in email and "." in email.split("@")[-1] and len(email) >= 5


def create_account(email, acct_type, password, facility="", contact="", user=""):
    """Create the local account tied to a Google/work email. Returns (ok, message)."""
    email = (email or "").strip()
    if not _valid_email(email):
        return False, "Please enter a valid email address."
    if len(str(password)) < 4:
        return False, "Please choose a password of at least 4 characters."
    set_setting("account_email", email)
    set_setting("account_type", acct_type or "Email")
    set_setting("account_created_at", datetime.now().isoformat(timespec="seconds"))
    set_account_password(password)
    set_setting("facility_name", (facility or "").strip())
    set_setting("facility_contact", (contact or "").strip())
    set_setting("current_user", (user or email.split("@")[0]).strip())
    audit("Create account", f"{acct_type or 'Email'}: {email}")
    return True, "Account created."


def set_account_password(password):
    import secrets
    salt = secrets.token_hex(8)
    set_setting("account_salt", salt)
    set_setting("account_pw_hash", _hash_pin(password, salt))
    audit("Set/change password")


def check_login(email, password):
    stored_email = get_setting("account_email", "").strip().lower()
    salt = get_setting("account_salt", "")
    stored = get_setting("account_pw_hash", "")
    return (stored_email == (email or "").strip().lower()
            and bool(stored) and _hash_pin(password, salt) == stored)


def account_email():
    return get_setting("account_email", "")


def account_type():
    return get_setting("account_type", "Email")


# ──────────────────────────────────────────────
# BULK IMPORT FROM A SPREADSHEET
# ──────────────────────────────────────────────
def import_items_df(df):
    """Create/update items from a dataframe. Returns (added, updated, errors[])."""
    added = updated = 0
    errors = []
    colmap = {str(c).strip().lower(): c for c in df.columns}

    def pick(*names):
        for n in names:
            if n in colmap:
                return colmap[n]
        return None

    c_name = pick("name", "item", "item name", "product")
    c_unit = pick("unit", "units", "uom")
    c_cat = pick("category", "type", "group")
    c_init = pick("initial_stock", "initial stock", "starting stock", "opening", "quantity", "qty")
    c_re = pick("reorder_pct", "reorder %", "reorder", "threshold", "reorder percent")
    c_exp = pick("expiry", "expiry date", "expires", "exp")
    if c_name is None:
        return 0, 0, ["No 'name' column found. Add a column headed 'name'."]

    for i, row in df.iterrows():
        try:
            name = str(row[c_name]).strip()
            if not name or name.lower() == "nan":
                continue

            def cell(col):
                """Spreadsheet value if the column exists and the cell isn't blank."""
                if not col or pd.isna(row[col]):
                    return None
                v = str(row[col]).strip()
                return v if v != "" else None

            unit_v = cell(c_unit)
            cat_v = cell(c_cat)
            init_v = cell(c_init)
            repct_v = cell(c_re)
            exp_v = cell(c_exp)
            exp_iso = None
            if exp_v is not None:
                d = _parse_date(exp_v[:10])
                exp_iso = d.isoformat() if d else None

            if item_exists(name):
                # Update only the fields the spreadsheet actually provides; keep the rest.
                ex = get_conn().execute(
                    "SELECT unit, category, initial_stock, reorder_pct, expiry "
                    "FROM items WHERE name=?", (name,)).fetchone()
                cur_unit, cur_cat, cur_init, cur_re, cur_exp = (
                    ex[0] or "", ex[1] or "", ex[2] or 0.0, ex[3] or 20.0, ex[4] or None)
                update_item(
                    name,
                    unit_v if unit_v is not None else cur_unit,
                    cat_v if cat_v is not None else cur_cat,
                    float(init_v) if init_v is not None else cur_init,
                    float(repct_v) if repct_v is not None else cur_re,
                    exp_iso if exp_v is not None else cur_exp)
                updated += 1
            else:
                add_item(name,
                         unit_v or "", cat_v or "",
                         float(init_v) if init_v is not None else 0.0,
                         float(repct_v) if repct_v is not None else 20.0,
                         exp_iso)
                added += 1
        except Exception as e:
            errors.append(f"Row {int(i) + 2}: {e}")
    if added or updated:
        audit("Bulk import", f"added {added}, updated {updated}")
    return added, updated, errors


# ──────────────────────────────────────────────
# VERSION / AUTO-UPDATE CHECK
# ──────────────────────────────────────────────
APP_VERSION = "1.1.0"
UPDATE_REPO = "M03ALI/1alert-system"


def check_for_update(timeout=6):
    """Look up the latest GitHub release. Returns (status, latest_tag, url).
    status: 'update' / 'current' / 'offline' / 'error'. Needs internet (optional)."""
    import json
    import urllib.request
    api = f"https://api.github.com/repos/{UPDATE_REPO}/releases/latest"
    try:
        req = urllib.request.Request(api, headers={"Accept": "application/vnd.github+json",
                                                   "User-Agent": "StockInventory"})
        with urllib.request.urlopen(req, timeout=timeout) as r:
            data = json.loads(r.read().decode("utf-8"))
        tag = (data.get("tag_name") or "").lstrip("vV")
        url = data.get("html_url") or f"https://github.com/{UPDATE_REPO}/releases"
        if not tag:
            return "error", "", url

        def norm(v):
            parts = []
            for p in str(v).split("."):
                num = "".join(ch for ch in p if ch.isdigit())
                parts.append(int(num) if num else 0)
            return parts + [0] * (3 - len(parts))
        newer = norm(tag) > norm(APP_VERSION)
        return ("update" if newer else "current"), tag, url
    except Exception as e:
        msg = str(e).lower()
        if "name" in msg or "resolve" in msg or "url" in msg or "network" in msg \
                or "timed out" in msg or "connection" in msg:
            return "offline", "", f"https://github.com/{UPDATE_REPO}/releases"
        return "error", "", f"https://github.com/{UPDATE_REPO}/releases"


# ──────────────────────────────────────────────
# STATUS / ALERT LOGIC
# ──────────────────────────────────────────────
def classify(pct, remaining, reorder_pct, moderate_pct=50):
    """Return (level, colour). Below the reorder threshold (or empty) = red."""
    if remaining <= 0:
        return "Out of stock", DANGER
    if pct <= reorder_pct:
        return "Restock", DANGER
    if pct <= moderate_pct:
        return "Moderate", WARN
    return "Available", OK_GREEN


def level_emoji(level):
    return {"Out of stock": "🟥", "Restock": "🟥",
            "Moderate": "🟨", "Available": "🟩"}.get(level, "⬜")


def week_bounds(d):
    """Monday..Sunday containing date d."""
    monday = d - timedelta(days=d.weekday())
    return monday, monday + timedelta(days=6)


def month_bounds(d):
    """First..last day of the month containing date d."""
    first = d.replace(day=1)
    nxt = first.replace(year=first.year + 1, month=1) if first.month == 12 \
        else first.replace(month=first.month + 1)
    return first, nxt - timedelta(days=1)


def _created_on_or_before(v, as_of):
    """True if an item's created_at (any reasonable form) is on/before as_of.
    Unknown/blank creation dates are treated as 'always existed' so legacy items
    are never dropped from historical reports."""
    try:
        if not v:
            return True
        return date.fromisoformat(str(v)[:10]) <= as_of
    except Exception:
        return True


def period_movements(start, end):
    """Per-item quantities USED and RESTOCKED between start and end (inclusive)."""
    c = get_conn()
    p = (start.isoformat(), end.isoformat())
    u = pd.read_sql_query(
        "SELECT item_name, SUM(quantity) AS used FROM usage_log "
        "WHERE use_date BETWEEN ? AND ? GROUP BY item_name", c, params=p)
    r = pd.read_sql_query(
        "SELECT item_name, SUM(quantity) AS restocked FROM restock_log "
        "WHERE restock_date BETWEEN ? AND ? GROUP BY item_name", c, params=p)
    m = pd.merge(u, r, on="item_name", how="outer")
    if m.empty:
        return pd.DataFrame(columns=["item_name", "used", "restocked"])
    m["used"] = m["used"].fillna(0.0)
    m["restocked"] = m["restocked"].fillna(0.0)
    return m.sort_values("used", ascending=False)


def compute_status(as_of=None, conn=None):
    """Detailed status for every item.

    total_in  = starting stock + everything restocked
    used      = everything logged as used
    remaining = total_in - used ; pct = remaining / total_in * 100

    If `as_of` (a date) is given, only logs on/before that date are counted, giving
    the inventory position *as of* the end of that day, and items created after that
    date are excluded — used for historical day/week/month reports.
    `conn` lets the status be computed from another database file (e.g. a saved
    inventory document) instead of the live working database.
    """
    c = conn if conn is not None else get_conn()
    use_cache = (conn is None and as_of is None)
    if use_cache:
        _key = (_DATA_VERSION, date.today().isoformat())
        if _STATUS_CACHE.get("key") == _key and _STATUS_CACHE.get("df") is not None:
            return _STATUS_CACHE["df"].copy()
    items = pd.read_sql_query("SELECT * FROM items", c)
    if items.empty:
        return pd.DataFrame()
    # be tolerant of an older schema that predates these columns
    for col, default in (("unit", ""), ("category", ""),
                         ("initial_stock", 0.0), ("reorder_pct", 20.0)):
        if col not in items.columns:
            items[col] = default

    if as_of is not None and "created_at" in items.columns:
        items = items[items["created_at"].apply(
            lambda v: _created_on_or_before(v, as_of))].copy()
        if items.empty:
            return pd.DataFrame()

    if as_of is None:
        used = pd.read_sql_query(
            "SELECT item_name, SUM(quantity) AS used, MAX(use_date) AS last_used, "
            "COUNT(*) AS use_events FROM usage_log GROUP BY item_name", c)
        added = pd.read_sql_query(
            "SELECT item_name, SUM(quantity) AS added, MAX(restock_date) AS last_restock "
            "FROM restock_log GROUP BY item_name", c)
    else:
        a = as_of.isoformat()
        used = pd.read_sql_query(
            "SELECT item_name, SUM(quantity) AS used, MAX(use_date) AS last_used, "
            "COUNT(*) AS use_events FROM usage_log WHERE use_date <= ? GROUP BY item_name",
            c, params=(a,))
        added = pd.read_sql_query(
            "SELECT item_name, SUM(quantity) AS added, MAX(restock_date) AS last_restock "
            "FROM restock_log WHERE restock_date <= ? GROUP BY item_name", c, params=(a,))

    df = items.merge(used, left_on="name", right_on="item_name", how="left")
    df = df.merge(added, left_on="name", right_on="item_name", how="left",
                  suffixes=("", "_r"))
    for col, default in (("used", 0.0), ("added", 0.0), ("use_events", 0)):
        df[col] = df[col].fillna(default)

    df["total_in"] = df["initial_stock"] + df["added"]
    df["remaining"] = df["total_in"] - df["used"]
    _tot = df["total_in"].where(df["total_in"] > 0)
    df["pct"] = (df["remaining"] / _tot * 100).fillna(0.0)

    levels, colors, suggest = [], [], []
    mod = moderate_threshold()
    for _, r in df.iterrows():
        lvl, col = classify(r["pct"], r["remaining"], r["reorder_pct"], mod)
        levels.append(lvl)
        colors.append(col)
        s = max(0.0, r["initial_stock"] - r["remaining"]) if lvl in (
            "Restock", "Out of stock") else 0.0
        suggest.append(s)
    df["level"] = levels
    df["color"] = colors
    df["suggest_order"] = suggest
    df["below_threshold"] = df["level"].isin(["Restock", "Out of stock"])
    df["category"] = df["category"].fillna("")
    df["unit"] = df["unit"].fillna("")
    df["last_used"] = df["last_used"].fillna("—")
    df["last_restock"] = df["last_restock"].fillna("—")

    # Expiry tracking
    if "expiry" not in df.columns:
        df["expiry"] = ""
    df["expiry"] = df["expiry"].fillna("")
    win = expiry_window_days()
    df["expiry_status"] = df["expiry"].apply(lambda e: expiry_status(e, window=win))

    # Days of stock left — average daily usage over the last 30 days, in ONE query
    # (instead of a separate query per item).
    since = (date.today() - timedelta(days=30)).isoformat()
    if as_of is None:
        u30 = pd.read_sql_query(
            "SELECT item_name, SUM(quantity) AS u30 FROM usage_log "
            "WHERE use_date >= ? GROUP BY item_name", c, params=(since,))
    else:
        lo = (as_of - timedelta(days=30)).isoformat()
        u30 = pd.read_sql_query(
            "SELECT item_name, SUM(quantity) AS u30 FROM usage_log "
            "WHERE use_date >= ? AND use_date <= ? GROUP BY item_name",
            c, params=(lo, as_of.isoformat()))
    rate = dict(zip(u30["item_name"], u30["u30"])) if not u30.empty else {}
    df["avg_daily"] = df["name"].map(lambda n: float(rate.get(n, 0.0) or 0.0) / 30.0)

    def _dleft(r):
        if r["avg_daily"] > 0 and r["remaining"] > 0:
            return r["remaining"] / r["avg_daily"]
        return float("inf") if r["remaining"] > 0 else 0.0
    df["days_left"] = df.apply(_dleft, axis=1)
    result = df.sort_values("pct").reset_index(drop=True)
    if use_cache:
        _STATUS_CACHE["key"] = (_DATA_VERSION, date.today().isoformat())
        _STATUS_CACHE["df"] = result.copy()
    return result


def fmt(x):
    try:
        x = float(x)
    except (TypeError, ValueError):
        return str(x)
    return f"{int(x):,}" if abs(x - round(x)) < 1e-9 else f"{x:,.2f}"


def search_filter(df, query, cols):
    if not query:
        return df
    q = query.strip().lower()
    mask = pd.Series(False, index=df.index)
    for col in cols:
        if col in df.columns:
            mask = mask | df[col].astype(str).str.lower().str.contains(q, na=False)
    return df[mask]


def alert_bar(row):
    """Coloured bar with the actual count and percentage left before depletion."""
    name, unit = row["name"], (row["unit"] or "")
    remaining, total, pct = row["remaining"], row["total_in"], row["pct"]
    level, color = row["level"], row["color"]
    fill = max(0.0, min(100.0, pct))
    unit_txt = f" {unit}" if unit else ""
    cat = f' &nbsp;·&nbsp; <span style="color:{MUTED_FG};">{row["category"]}</span>' if row["category"] else ""
    suggest = (f' &nbsp;·&nbsp; <span style="color:{DANGER};">order ~{fmt(row["suggest_order"])}</span>'
               if row["suggest_order"] > 0 else "")
    label = f'{fmt(max(remaining, 0))} / {fmt(total)}{unit_txt} left &nbsp;·&nbsp; {pct:.0f}%'
    st.markdown(f"""
    <div style="border:1px solid {BORDER}; border-radius:12px; padding:10px 14px;
                margin-bottom:10px; background:{SURFACE}; box-shadow:0 2px 8px rgba(6,52,58,.05);">
      <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:6px;">
        <span style="font-weight:700; color:{BODY_FG};">{name}{cat}</span>
        <span class="chip" style="background:{color};">{level}</span>
      </div>
      <div style="position:relative; height:28px; background:{TRACK_BG};
                  border-radius:999px; overflow:hidden;">
        <div style="width:{fill}%; height:100%; background:{color};
                    border-radius:999px; transition:width .3s;"></div>
        <span style="position:absolute; inset:0; display:flex; align-items:center;
                     justify-content:center; font-weight:700; font-size:.85rem;
                     color:{BODY_FG};">{label}</span>
      </div>
      <div style="margin-top:5px; font-size:.78rem; color:{MUTED_FG};">
        Reorder at {fmt(row["reorder_pct"])}% &nbsp;·&nbsp; used {fmt(row["used"])}
        &nbsp;·&nbsp; last used {row["last_used"]}{suggest}
      </div>
    </div>
    """, unsafe_allow_html=True)


def _days_left_str(v):
    try:
        v = float(v)
    except (TypeError, ValueError):
        return "—"
    if v == float("inf"):
        return "—"
    if v <= 0:
        return "0"
    return f"{int(round(v)):,}"


def detail_table(df):
    """A rich, friendly table with an in-cell progress bar for % remaining."""
    data = {
        "Status": [level_emoji(l) + " " + l for l in df["level"]],
        "Item": df["name"],
        "Category": df["category"],
        "Unit": df["unit"],
        "% left": df["pct"].round(0),
        "Remaining": df["remaining"].round(2),
        "Days left": df["days_left"].map(_days_left_str) if "days_left" in df
        else ["—"] * len(df),
        "Total stock": df["total_in"].round(2),
        "Used": df["used"].round(2),
        "Restocked": df["added"].round(2),
        "Starting": df["initial_stock"].round(2),
        "Reorder %": df["reorder_pct"].round(0),
        "Expiry": df["expiry"] if "expiry" in df else ["" for _ in range(len(df))],
        "Expiry status": df["expiry_status"] if "expiry_status" in df
        else ["" for _ in range(len(df))],
        "Last used": df["last_used"],
        "Last restocked": df["last_restock"],
    }
    disp = pd.DataFrame(data)
    st.dataframe(
        disp, use_container_width=True, hide_index=True,
        column_config={
            "% left": st.column_config.ProgressColumn(
                "% left", min_value=0, max_value=100, format="%d%%"),
            "Days left": st.column_config.TextColumn(
                "Days left", help="Estimated days until empty at the recent usage rate."),
        })


def overview_chart(df):
    d = df.sort_values("pct")
    fig = go.Figure()
    fig.add_bar(
        x=d["remaining"].clip(lower=0), y=d["name"], orientation="h",
        marker_color=list(d["color"]),
        text=[f"{fmt(r)} / {fmt(t)}" for r, t in zip(d["remaining"], d["total_in"])],
        textposition="auto", insidetextanchor="middle",
        hovertext=[f"{n}: {fmt(r)} of {fmt(t)} left ({p:.0f}%)"
                   for n, r, t, p in zip(d["name"], d["remaining"], d["total_in"], d["pct"])],
        hoverinfo="text", name="Remaining")
    fig.add_scatter(
        x=d["total_in"], y=d["name"], mode="markers", name="Total stock",
        marker=dict(symbol="line-ns-open", size=18, color=BODY_FG, line=dict(width=2, color=BODY_FG)))
    fig.update_layout(
        title="Units remaining vs total stock",
        paper_bgcolor=CHART_BG, plot_bgcolor=CHART_BG, font=dict(color=BODY_FG),
        title_font=dict(color=PRIMARY), height=max(280, 42 * len(d) + 100),
        margin=dict(l=10, r=20, t=60, b=40), bargap=0.35,
        legend=dict(orientation="h", yanchor="bottom", y=1.02, x=1, xanchor="right"))
    fig.update_xaxes(showline=True, linecolor=AXIS, linewidth=1.2, mirror=True,
                     showgrid=False, zeroline=False, automargin=True)
    fig.update_yaxes(showline=True, linecolor=AXIS, linewidth=1.2, mirror=True,
                     showgrid=False, zeroline=False, automargin=True, autorange="reversed")
    return fig


def log_history_view(table, name_col, date_col, qty_col, key):
    """Shared 'history with filters' UI for usage_log / restock_log: a product-name
    search box and a from/to date filter over a log table. Returns the filtered df."""
    raw = pd.read_sql_query(f"SELECT * FROM {table}", get_conn())
    if raw.empty:
        st.caption("Nothing recorded yet.")
        return raw

    raw["_d"] = pd.to_datetime(raw[date_col], errors="coerce")
    dmin = raw["_d"].min().date()
    dmax = raw["_d"].max().date()

    f1, f2, f3 = st.columns([3, 2, 2])
    q = f1.text_input("🔎 Search product name", key=f"{key}_q",
                      placeholder="Type a product name…")
    start = f2.date_input("From", value=dmin, key=f"{key}_from")
    end = f3.date_input("To", value=dmax, key=f"{key}_to")

    df = raw.copy()
    if q.strip():
        df = df[df[name_col].astype(str).str.lower().str.contains(q.strip().lower(), na=False)]
    df = df[(df["_d"].dt.date >= start) & (df["_d"].dt.date <= end)]
    df = df.sort_values([date_col, "id"], ascending=[False, False])

    if df.empty:
        st.info("No records match those filters.")
        return df

    out = pd.DataFrame({
        "Date": df[date_col],
        "Product": df[name_col],
        "Quantity": df[qty_col].map(fmt),
        "Note": df.get("note", pd.Series([""] * len(df))).fillna(""),
        "Recorded by": df.get("recorded_by", pd.Series([""] * len(df))).fillna(""),
    })
    total = df[qty_col].sum()
    st.caption(f"Showing **{len(df)}** record(s) · total **{fmt(total)}** units "
               f"between {start:%d %b %Y} and {end:%d %b %Y}.")
    st.dataframe(out, use_container_width=True, hide_index=True)
    st.download_button("⬇️ Download filtered records (CSV)",
                       out.to_csv(index=False).encode("utf-8"),
                       file_name=f"{table}_filtered.csv", mime="text/csv", key=f"{key}_dl")
    return df


def edit_entry_ui(table, name_col, date_col, qty_col, key):
    """Let the user correct or remove a past usage/restock entry."""
    rows = pd.read_sql_query(
        f"SELECT id, {name_col} AS nm, {date_col} AS dt, {qty_col} AS qty, "
        f"COALESCE(note,'') AS note FROM {table} ORDER BY {date_col} DESC, id DESC LIMIT 300",
        get_conn())
    if rows.empty:
        st.caption("Nothing to edit yet.")
        return
    labels = {f"#{int(r.id)} · {r.dt} · {r.nm} · {fmt(r.qty)}": int(r.id)
              for r in rows.itertuples()}
    pick = st.selectbox("Choose an entry to correct", list(labels.keys()), key=f"{key}_pick")
    eid = labels[pick]
    cur = rows[rows["id"] == eid].iloc[0]
    g1, g2 = st.columns(2)
    new_d = g1.date_input("Date", value=(_parse_date(cur["dt"]) or date.today()),
                          key=f"{key}_d")
    new_q = g2.number_input("Quantity", min_value=0.0, value=float(cur["qty"]),
                            step=1.0, key=f"{key}_q")
    new_note = st.text_input("Note", value=str(cur["note"]), key=f"{key}_note")
    a1, a2 = st.columns(2)
    if a1.button("💾 Save correction", key=f"{key}_save", use_container_width=True):
        if new_q <= 0:
            st.warning("Quantity must be greater than zero (use Delete to remove an entry).")
        else:
            update_log_entry(table, eid, new_d, new_q, new_note.strip())
            st.success("Entry corrected.")
            st.rerun()
    if a2.button("🗑️ Delete this entry", key=f"{key}_del", use_container_width=True):
        delete_log_entry(table, eid)
        st.success("Entry deleted.")
        st.rerun()


