def build_dashboard_report(status, report_title="Inventory Dashboard Report",
                           period_line=None, movements=None, movements_label="this period",
                           inventory_name=None):
    """A self-contained, print-ready HTML report: branding, summary counts, the
    below-threshold reorder list and the full inventory table. Optionally shows a
    period line under the title and a 'movements' section (used / restocked in the
    chosen day, week or month). HTML so it needs no extra libraries; open it in a
    browser or print / save it as PDF."""
    now = datetime.now()
    below = status[status["below_threshold"]]
    out = status[status["remaining"] <= 0]
    low = status[status["level"] == "Moderate"]
    healthy = status[status["level"] == "Available"]

    def chip(level):
        c = {"Out of stock": DANGER, "Restock": DANGER,
             "Moderate": WARN, "Available": OK_GREEN}.get(level, MUTED)
        return (f'<span style="background:{c};color:#fff;padding:2px 8px;border-radius:999px;'
                f'font-size:11px;font-weight:700;">{level}</span>')

    head = "<tr>" + "".join(f"<th>{h}</th>" for h in
        ["Item", "Category", "Remaining", "Total", "% left", "Reorder %",
         "Suggest order", "Status"]) + "</tr>"

    def rows(df):
        cells = []
        for _, r in df.iterrows():
            unit = f' {r["unit"]}' if r["unit"] else ""
            sugg = fmt(r["suggest_order"]) if r["suggest_order"] > 0 else "—"
            cells.append(
                "<tr>"
                f'<td>{r["name"]}</td>'
                f'<td>{r["category"] or "—"}</td>'
                f'<td style="text-align:right;">{fmt(max(r["remaining"], 0))}{unit}</td>'
                f'<td style="text-align:right;">{fmt(r["total_in"])}</td>'
                f'<td style="text-align:right;">{r["pct"]:.0f}%</td>'
                f'<td style="text-align:right;">{fmt(r["reorder_pct"])}%</td>'
                f'<td style="text-align:right;">{sugg}</td>'
                f"<td>{chip(r['level'])}</td>"
                "</tr>")
        return "".join(cells)

    def metric(label, val, color=PRIMARY):
        return (f'<div style="flex:1;min-width:120px;border:1px solid {GRID};border-radius:12px;'
                f'padding:10px 14px;text-align:center;">'
                f'<div style="font-size:24px;font-weight:800;color:{color};">{val}</div>'
                f'<div style="font-size:12px;color:{MUTED};">{label}</div></div>')

    below_section = (
        f'<p style="color:{OK_GREEN};font-weight:700;">✓ Nothing is below its reorder '
        f"threshold.</p>" if below.empty else f"<table>{head}{rows(below)}</table>")

    # Optional movements section (used / restocked within the chosen period).
    movements_section = ""
    if movements is not None:
        mv = movements[(movements["used"] > 0) | (movements["restocked"] > 0)] \
            if not movements.empty else movements
        if mv is None or mv.empty:
            movements_section = (
                f'<h2>Stock movements ({movements_label})</h2>'
                f'<p class="muted">No usage or restocking was recorded in this period.</p>')
        else:
            mhead = ("<tr><th>Item</th><th>Used</th><th>Restocked</th>"
                     "<th>Net change</th></tr>")
            mrows = []
            for _, r in mv.iterrows():
                net = r["restocked"] - r["used"]
                net_col = OK_GREEN if net >= 0 else DANGER
                mrows.append(
                    "<tr>"
                    f'<td>{r["item_name"]}</td>'
                    f'<td style="text-align:right;">{fmt(r["used"])}</td>'
                    f'<td style="text-align:right;">{fmt(r["restocked"])}</td>'
                    f'<td style="text-align:right;color:{net_col};font-weight:700;">'
                    f'{"+" if net >= 0 else ""}{fmt(net)}</td>'
                    "</tr>")
            tot_u = fmt(mv["used"].sum())
            tot_r = fmt(mv["restocked"].sum())
            movements_section = (
                f'<h2>Stock movements ({movements_label})</h2>'
                f'<table>{mhead}{"".join(mrows)}</table>'
                f'<p class="muted">Total used: <b>{tot_u}</b> &nbsp;·&nbsp; '
                f'total restocked: <b>{tot_r}</b>.</p>')

    period_html = (f'<div class="muted" style="font-weight:700;color:{INK};'
                   f'font-size:13px;">{period_line}</div>' if period_line else "")
    inv_html = (f'<div style="font-weight:800;color:{PRIMARY};font-size:16px;'
                f'margin:2px 0 4px 0;">Inventory: {inventory_name}</div>'
                if inventory_name else "")
    doc_title = f"{inventory_name} — {report_title}" if inventory_name else report_title

    html = f"""<!DOCTYPE html><html><head><meta charset="utf-8">
<title>{doc_title}</title>
<style>
  body {{ font-family:system-ui,-apple-system,Segoe UI,Roboto,sans-serif; color:{INK}; margin:28px; }}
  h1 {{ color:{PRIMARY}; margin:6px 0; }}
  h2 {{ color:{PRIMARY}; border-bottom:2px solid {LIGHT_BG}; padding-bottom:4px; margin-top:26px; }}
  table {{ border-collapse:collapse; width:100%; font-size:13px; margin-top:8px; }}
  th {{ background:{PRIMARY}; color:#fff; text-align:left; padding:7px 9px; }}
  td {{ border-bottom:1px solid {GRID}; padding:6px 9px; }}
  tr:nth-child(even) td {{ background:{LIGHT_BG}; }}
  .muted {{ color:{MUTED}; font-size:12px; }}
  .brand {{ text-align:center; margin-bottom:8px; }}
  @media print {{ body {{ margin:10mm; }} }}
</style></head><body>
  <div class="brand">
    <div style="font-size:11px;font-weight:800;letter-spacing:.12em;text-transform:uppercase;
                color:{MUTED};">Powered by Health Data Matrics</div>
    <img src="data:image/png;base64,{HDM_LOGO_B64}" style="height:60px;" alt="Health Data Matrics"/>
  </div>
  <h1>{report_title}</h1>
  {inv_html}
  {period_html}
  <div class="muted">Generated {now:%A, %d %B %Y at %H:%M}</div>
  <div style="display:flex;gap:10px;flex-wrap:wrap;margin-top:14px;">
    {metric("Items tracked", len(status))}
    {metric("Restock", len(below), DANGER)}
    {metric("Out of stock", len(out), DANGER)}
    {metric("Moderate", len(low), WARN)}
    {metric("Available", len(healthy), OK_GREEN)}
  </div>
  <h2>Needs restocking — reorder needed</h2>
  {below_section}
  {movements_section}
  <h2>Full inventory{(" — position as of " + period_line.split("· ")[-1]) if period_line else ""}</h2>
  <table>{head}{rows(status)}</table>
  <p class="muted" style="margin-top:24px;">“Suggest order” brings an item back up to its
  starting level. Stock levels reflect all usage and restocking up to the report date.</p>
</body></html>"""
    return html.encode("utf-8")


