# INVENTORY DOCUMENTS  (Excel-style Save / Open of the whole working state)
# ──────────────────────────────────────────────
DOCS_DIR = os.path.join(os.path.expanduser("~"), "StockInventory", "Documents")
DOC_EXT = ".invdb"


def list_documents():
    """Filenames of saved inventory documents in the Documents folder."""
    try:
        os.makedirs(DOCS_DIR, exist_ok=True)
        return sorted(f for f in os.listdir(DOCS_DIR)
                      if f.lower().endswith((".invdb", ".db")))
    except Exception:
        return []


def save_document(path):
    """Write the current working state to a document file (a clean SQLite copy)."""
    import sqlite3
    folder = os.path.dirname(path)
    if folder:
        os.makedirs(folder, exist_ok=True)
    dst = sqlite3.connect(path)
    try:
        with dst:
            get_conn().backup(dst)
    finally:
        dst.close()


def load_document(path):
    """Open a document file as the current working state (replaces working data)."""
    import shutil
    try:
        get_conn().close()
    except Exception:
        pass
    try:
        get_conn.clear()
    except Exception:
        pass
    shutil.copyfile(path, DB_PATH)
    for ext in ("-wal", "-shm"):
        try:
            os.remove(DB_PATH + ext)
        except Exception:
            pass
    init_db()  # reconnects to the new file and makes sure the schema is current


def downloads_dir():
    """The computer's Downloads folder (created if needed); falls back to home."""
    target = os.path.join(os.path.expanduser("~"), "Downloads")
    try:
        os.makedirs(target, exist_ok=True)
        return target
    except Exception:
        return os.path.expanduser("~")


def save_report_to_downloads(report_bytes, filename):
    """Write an HTML report straight to the Downloads folder. Returns the path."""
    path = os.path.join(downloads_dir(), filename)
    with open(path, "wb") as f:
        f.write(report_bytes)
    return path


def open_path(path):
    """Open a file or folder with the computer's default program (local app)."""
    import sys as _sys
    import subprocess as _sp
    try:
        if _sys.platform.startswith("win"):
            os.startfile(path)  # noqa: B606  (Windows only)
        elif _sys.platform == "darwin":
            _sp.Popen(["open", path])
        else:
            _sp.Popen(["xdg-open", path])
        return True
    except Exception:
        try:
            import webbrowser
            webbrowser.open("file://" + os.path.abspath(path))
            return True
        except Exception:
            return False


def offer_open(path, where="Downloads"):
    """Remember the freshly saved file and show a corner toast to open it."""
    st.session_state["last_saved_file"] = path
    try:
        st.toast(f"Report saved to {where}. Click “Open report” to view it.", icon="✅")
    except Exception:
        pass


def render_open_controls(key_prefix):
    """Show 'Open report' / 'Open Downloads folder' for the last saved report."""
    p = st.session_state.get("last_saved_file")
